   100→  error AmountBelowMinAuctionSize(uint256 amountUsdValue, uint256 minAuctionSizeUsd);
   101→
   102→  // @notice Parameters to initialize the contract in the constructor.
   103→  // solhint-disable-next-line gas-struct-packing
   104→  struct ConstructorParams {
   105→    address admin; // ────────────────────────────────────╮
   106→    // The initial contract admin.
   107→    uint48 adminRoleTransferDelay; // ────────────────────╯ The min seconds
   108→    // before the admin address can be transferred.
   109→    uint64 minPriceMultiplier; // ────────────────────────╮ The
   110→    // auction price multiplier lower bound in basis points
   111→    //                                                    │ used for input validation of all assets configured in the
   112→    //                                                    │ contract.
   113→    address verifierProxy; // ────────────────────────────╯
   114→    // The address of the Data Streams VerifierProxy contract.
   115→    uint88 minBidUsdValue; // ────────────────────────────╮
   116→    // The minimum bid USD value in 18 decimals.
   117→    address linkToken; // ────────────────────────────────╯
   118→    // The address of the LINK token contract.
   119→    address assetOut; //                                    The asset out of all the auctions.
   120→    address assetOutReceiver; //                            The asset out receiver.
   121→    address feeAggregator; //                               The fee aggregator.
   122→    PriceManager.ApplyFeedInfoUpdateParams[] feedInfos; //  The initial feed info list.
   123→  }
   124→
   125→  /// @notice The auction parameters of an asset.
   126→  /// @dev The decay rate per second is applied linearly to the starting price multiplier.
   127→  /// @dev Asset parameters should also be configured for the asset out. Although it is not auctioned, the min auction
   128→  /// size and decimals fields are still used.
   129→  /// Example:
   130→  ///   - startingPriceMultiplier = 1.1e18 (10% premium)
   131→  ///   - endingPriceMultiplier = 0.98e18 (2% discount)
   132→  ///   - auctionDuration = 3600 (1 hour)
   133→  ///   - decayRatePerSecond = (1.1e18 - 0.98e18) / 3600 = 33333333333333 (rounded down to avoid higher
   134→  ///     discount than 2%)
   135→  struct AssetParams {
   136→    uint96 minAuctionSizeUsd; // ───────╮ The minimum swap size expressed in USD feed decimals.
   137→    uint64 startingPriceMultiplier; //  │ The starting price multiplier with 18 decimals precision.
   138→    uint64 endingPriceMultiplier; //    │ The ending price multiplier with 18 decimals precision.
   139→    uint24 auctionDuration; //          │ The duration of the auction in seconds.
   140→    uint8 decimals; //  ────────────────╯ The asset decimals.
   141→  }
   142→
   143→  /// @notice The parameters for adding or updating asset parameters.
   144→  struct ApplyAssetParamsUpdate {
   145→    address asset; // The address of the asset.
   146→    AssetParams params; // The asset parameters.
   147→  }
   148→
   149→  /// @inheritdoc ITypeAndVersion
   150→  string public constant override typeAndVersion = "Auction 1.0.0-dev";
   151→
   152→  /// @notice The auction price multiplier lower bound in 18 decimals used for input validation of all assets configured
   153→  /// in the contract - e.g. 0.98e18 represents a maximum discount of 2%.
   154→  uint64 internal immutable i_minPriceMultiplier;
   155→
   156→  /// @notice Reentrant flag.
   157→  bool internal s_entered;
   158→  /// @notice The minimum bid USD value in 18 decimals.
   159→  uint88 internal s_minBidUsdValue;
   160→  /// @notice The asset out of all the auctions.
   161→  address internal s_assetOut;
   162→  /// @notice The receiver of to tokens.
   163→  address internal s_assetOutReceiver;
   164→  /// @notice The fee aggregator
   165→  IFeeAggregator internal s_feeAggregator;
   166→
   167→  /// @notice Mapping from `from` token to its struct.
   168→  mapping(address asset => AssetParams params) internal s_assetParams;
   169→  /// @notice Mapping from `from` token to the auction start timestamp.
   170→  mapping(address asset => uint256 auctionStart) internal s_auctionStarts;
   171→
   172→  modifier whenAssetOutConfigured() {
   173→    if (s_assetParams[s_assetOut].decimals == 0) {
   174→      revert MissingAssetOutParams();
   175→    }
   176→    _;
   177→  }
   178→
   179→  constructor(
   180→    ConstructorParams memory params
   181→  )
   182→    PriceManager(params.adminRoleTransferDelay, params.admin, params.verifierProxy, params.linkToken, params.feedInfos)
   183→  {
   184→    if (params.assetOut == address(0) || params.assetOutReceiver == address(0)) {
   185→      revert Errors.InvalidZeroAddress();
   186→    }
   187→
   188→    _setMinBidUsdValue(params.minBidUsdValue);
   189→    _setAssetOut(params.assetOut);
   190→    _setAssetOutReceiver(params.assetOutReceiver);
   191→    _setFeeAggregator(params.feeAggregator);
   192→
   193→    if (params.minPriceMultiplier == 0) {
   194→      revert Errors.InvalidZeroValue();
   195→    }
   196→
   197→    i_minPriceMultiplier = params.minPriceMultiplier;
   198→
   199→    emit MinPriceMultiplierSet(params.minPriceMultiplier);
   200→  }
   201→
   202→  /// @inheritdoc IBaseAuction
   203→  /// @dev This function checks for eligible assets to start auctions and ended auctions to be closed.
